@@ -900,6 +900,82 @@
-  grd.addColorStop(0, 'rgba(255, 200, 80, 0.08)'); grd.addColorStop(1, 'rgba(255, 200, 80, 0)');
+  grd.addColorStop(0, 'rgba(255, 200, 80, 0.08)'); grd.addColorStop(1, 'rgba(255, 200, 80, 0)');
+}
+
+const medievalQuips = [
+  "By my troth!",
+  "Zounds!",
+  "Fie on't!",
+  "God's wounds!",
+  "Gramercy!",
+  "Marry, well said!",
+  "Prithee, listen.",
+  "Anon, anon!",
+  "Hark ye!",
+  "Forsooth!",
+  "Alack, alack!",
+  "Hie thee hither!",
+  "Thou art a knave!",
+  "Methinks so.",
+  "What ho!",
+  "Gramercy, good sir.",
+  "Soft, what light?",
+  "By my faith!",
+  "Fare thee well.",
+];
+
+let bubbleTimeouts = new Map<CanvasRenderingContext2D, number>();
+
+function drawSpeechBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string, isThought: boolean) {
+  // Bubble max width and padding
+  const maxWidth = 160;
+  const paddingX = 6;
+  const paddingY = 4;
+  ctx.font = '12px monospace';
+  // Truncate text to 30 chars max
+  if (text.length > 30) text = text.slice(0, 30) + '…';
+  // Measure text width
+  let textWidth = ctx.measureText(text).width;
+  if (textWidth > maxWidth) textWidth = maxWidth;
+  const bubbleWidth = textWidth + paddingX * 2;
+  const bubbleHeight = 20;
+
+  // Bubble position above character
+  const bx = x - bubbleWidth / 2;
+  const by = y - bubbleHeight - 18;
+
+  // Clear previous bubble area (optional, depends on render loop)
+  // ctx.clearRect(bx - 2, by - 2, bubbleWidth + 4, bubbleHeight + 20);
+
+  // Draw bubble shape: rounded rect with pointer
+  const radius = 6;
+  ctx.beginPath();
+  // Rounded rect
+  ctx.moveTo(bx + radius, by);
+  ctx.lineTo(bx + bubbleWidth - radius, by);
+  ctx.quadraticCurveTo(bx + bubbleWidth, by, bx + bubbleWidth, by + radius);
+  ctx.lineTo(bx + bubbleWidth, by + bubbleHeight - radius);
+  ctx.quadraticCurveTo(bx + bubbleWidth, by + bubbleHeight, bx + bubbleWidth - radius, by + bubbleHeight);
+  ctx.lineTo(bx + bubbleWidth / 2 + 8, by + bubbleHeight);
+  // Pointer triangle
+  ctx.lineTo(bx + bubbleWidth / 2, by + bubbleHeight + 8);
+  ctx.lineTo(bx + bubbleWidth / 2 - 8, by + bubbleHeight);
+  //
+  ctx.lineTo(bx + radius, by + bubbleHeight);
+  ctx.quadraticCurveTo(bx, by + bubbleHeight, bx, by + bubbleHeight - radius);
+  ctx.lineTo(bx, by + radius);
+  ctx.quadraticCurveTo(bx, by, bx + radius, by);
+  ctx.closePath();
+
+  // Fill white
+  ctx.fillStyle = '#ffffff';
+  ctx.fill();
+  // Border dark 1px
+  ctx.lineWidth = 1;
+  ctx.strokeStyle = '#202020';
+  ctx.stroke();
+
+  // Draw text inside bubble
+  ctx.fillStyle = '#202020';
+  ctx.textBaseline = 'middle';
+  ctx.textAlign = 'center';
+  ctx.fillText(text, bx + bubbleWidth / 2, by + bubbleHeight / 2);
+
+  // Thought bubble effect: if isThought, draw small circles below pointer
+  if (isThought) {
+    const cx = bx + bubbleWidth / 2;
+    const cy = by + bubbleHeight + 8;
+    ctx.beginPath();
+    ctx.fillStyle = '#ffffff';
+    ctx.strokeStyle = '#202020';
+    ctx.lineWidth = 1;
+    for (let i = 0; i < 3; i++) {
+      const r = 4 - i;
+      const px = cx + i * 8 - 8;
+      const py = cy + i * 6;
+      ctx.moveTo(px + r, py);
+      ctx.arc(px, py, r, 0, Math.PI * 2);
+      ctx.fill();
+      ctx.stroke();
+    }
+  }
+}
+
+function renderCharacterSpeech(ctx: CanvasRenderingContext2D, character: any, x: number, y: number) {
+  // character: { taskTitle?: string, idle: boolean }
+  // Show speech bubble with current task or idle quip
+  let text = '';
+  let isThought = false;
+  if (character.taskTitle && character.taskTitle.length > 0) {
+    text = character.taskTitle.length > 30 ? character.taskTitle.slice(0, 30) + '…' : character.taskTitle;
+    isThought = false;
+  } else if (character.idle) {
+    // Pick random quip
+    text = medievalQuips[Math.floor(Math.random() * medievalQuips.length)];
+    isThought = true;
+  } else {
+    return; // no bubble
+  }
+
+  // Draw bubble
+  drawSpeechBubble(ctx, x, y, text, isThought);
+
+  // Auto-hide bubble after 3 seconds
+  if (bubbleTimeouts.has(ctx)) {
+    clearTimeout(bubbleTimeouts.get(ctx));
+  }
+  const timeoutId = window.setTimeout(() => {
+    // Clear bubble by redrawing character or clearing area - depends on render loop
+    // Here we just remove timeout reference
+    bubbleTimeouts.delete(ctx);
+  }, 3000);
+  bubbleTimeouts.set(ctx, timeoutId);
+}
+
